const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;
const config = body.config || {};

if (!tenantId || !automationId) {
  return [{ json: { valid: false, error: 'tenantId et automationId requis' } }];
}

return [{ json: { tenantId, automationId, config, valid: true } }];

const catalogRow = $('04. Chercher catalogue + tenant').first().json;
const existingPurchase = $('05. Verifier achat existant').first().json;
const data = $('02. Valider donnees').first().json;

if (!catalogRow || !catalogRow.code) {
  return [{ json: { valid: false, error: 'Automatisation ou tenant introuvable' } }];
}

const tenantName = catalogRow.tenant_name || 'Client';
const automationCode = catalogRow.code;
const automationNom = catalogRow.nom;
const setupPrice = catalogRow.setup_price || 0;
const monthlyPrice = catalogRow.monthly_price || 0;
const clientTag = `client:${tenantName}`;
const existingWorkflowIds = existingPurchase?.n8n_workflow_ids || [];

return [{ json: {
  valid: true,
  tenantId: data.tenantId,
  automationId: data.automationId,
  automationCode,
  automationNom,
  tenantName,
  setupPrice,
  monthlyPrice,
  config: data.config,
  clientTag,
  existingWorkflowIds
} }];

const apiResult = $input.first().json;
const data = $('06. Preparer donnees workflow').first().json;
const workflowId = apiResult.id ? String(apiResult.id) : null;
const workflowName = apiResult.name || null;
const existingIds = data.existingWorkflowIds || [];
const allWorkflowIds = workflowId ? [...existingIds, workflowId] : existingIds;

return [{ json: {
  success: !!workflowId,
  workflowId,
  workflowName,
  allWorkflowIds,
  tenantId: data.tenantId,
  automationId: data.automationId,
  automationCode: data.automationCode,
  automationNom: data.automationNom,
  tenantName: data.tenantName,
  setupPrice: data.setupPrice,
  monthlyPrice: data.monthlyPrice,
  config: data.config,
  clientTag: data.clientTag
} }];

const data = $('09. Verifier creation').first().json;
const purchaseResult = $input.first().json;

return [{ json: {
  success: data.success,
  workflowId: data.workflowId,
  workflowName: data.workflowName,
  clientTag: data.clientTag,
  tenantId: data.tenantId,
  automationCode: data.automationCode,
  workflowIds: data.allWorkflowIds || [],
  purchaseId: purchaseResult.id || null,
  purchaseStatus: purchaseResult.status || 'active',
  message: data.success
    ? 'Workflow ' + data.workflowName + ' cree. Achat enregistre.'
    : 'Erreur lors de la creation du workflow'
} }];
